import React from 'react';
import { Link } from 'react-router-dom';
import { UserPlus } from 'lucide-react';

const RegisterPage = () => {
  return (
    <div className="min-h-screen flex items-center justify-center p-6">
      <div className="w-full max-w-md cyber-card">
        <div className="text-center mb-8">
          <div className="flex justify-center mb-4 text-purple-400">
            <UserPlus size={32} />
          </div>
          <h2 className="text-3xl font-light tracking-tight text-white mb-2">Create Account</h2>
          <p className="text-white/40 text-xs uppercase tracking-widest">Initialize your node identity</p>
        </div>

        <form className="space-y-4">
          <input type="text" className="cyber-input" placeholder="Full Name" />
          <input type="email" className="cyber-input" placeholder="Email Address" />
          <input type="password" className="cyber-input" placeholder="Password" />
          <input type="password" className="cyber-input" placeholder="Confirm Password" />
          <button className="cyber-btn mt-6">Sign Up</button>
        </form>

        <p className="text-center mt-8 text-[10px] text-white/30 uppercase tracking-[0.2em]">
          Already registered? <Link to="/login" className="text-purple-400 hover:underline">Sign In</Link>
        </p>
      </div>
    </div>
  );
};
